{
  "mode": "method",
  "tests": [
    {
      "name": "basic_azure_setup",
      "input": {
        "resources": {
          "vm": 2,
          "storage": 1,
          "network": 1
        },
        "region": "eastus"
      },
      "output": {
        "status": "success",
        "message": "Resources provisioned successfully"
      },
      "notes": "Validates basic provisioning of Azure resources."
    },
    {
      "name": "terraform_integration",
      "input": {
        "terraform_code": "resource \"azurerm_virtual_machine\" \"example\" { ... }"
      },
      "output": {
        "status": "success",
        "message": "Terraform applied successfully"
      },
      "notes": "Checks if Terraform code can be applied without errors."
    },
    {
      "name": "ci_cd_pipeline_creation",
      "input": {
        "pipeline_config": {
          "steps": ["build", "test", "deploy"],
          "environment": "production"
        }
      },
      "output": {
        "status": "success",
        "message": "CI/CD pipeline created successfully"
      },
      "notes": "Ensures CI/CD pipeline can be created and configured."
    },
    {
      "name": "policy_enforcement",
      "input": {
        "policy": {
          "name": "enforce_tags",
          "rules": {
            "required_tags": ["environment", "owner"]
          }
        }
      },
      "output": {
        "status": "success",
        "message": "Policy enforced successfully"
      },
      "notes": "Validates that governance policies can be enforced."
    },
    {
      "name": "edge_case_no_resources",
      "input": {
        "resources": {}
      },
      "output": {
        "status": "error",
        "message": "No resources specified"
      },
      "notes": "Tests handling of an empty resource specification."
    },
    {
      "name": "adversarial_case_invalid_region",
      "input": {
        "resources": {
          "vm": 1
        },
        "region": "invalid-region"
      },
      "output": {
        "status": "error",
        "message": "Invalid region specified"
      },
      "notes": "Checks response to an invalid Azure region."
    },
    {
      "name": "monitoring_setup",
      "input": {
        "monitoring": {
          "enabled": true,
          "services": ["Azure Monitor", "Azure Backup"]
        }
      },
      "output": {
        "status": "success",
        "message": "Monitoring setup completed"
      },
      "notes": "Validates the setup of monitoring services."
    },
    {
      "name": "remote_collaboration",
      "input": {
        "team_members": ["architect", "security", "operations"],
        "availability": "overlap"
      },
      "output": {
        "status": "success",
        "message": "Collaboration established successfully"
      },
      "notes": "Ensures remote collaboration setup is validated."
    }
  ],
  "assumptions": "All inputs are valid JSON objects and conform to expected formats.",
  "notes": "Tests cover a range of scenarios including basic functionality and edge cases."
}
